use crate::helpers::spawn_app;

#[tokio::test]
async fn index_returns_200_with_html_content() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let content_type = response
        .headers()
        .get("content-type")
        .expect("Missing content-type header")
        .to_str()
        .unwrap();
    assert!(
        content_type.contains("text/html"),
        "Expected text/html, got {content_type}"
    );

    let body = response.text().await.unwrap();
    assert!(body.contains("<!DOCTYPE html>"), "Missing DOCTYPE");
    assert!(body.contains("<html lang=\"en\">"), "Missing html lang");
    assert!(
        body.contains("class=\"skip-link\""),
        "Skip link must use .skip-link class for focus reveal"
    );
    assert!(
        body.contains("Skip to main content"),
        "Missing skip link text"
    );
    assert!(
        body.contains("id=\"main-content\""),
        "Missing main content landmark"
    );
    assert!(body.contains("<header>"), "Missing header landmark");
    assert!(body.contains("<main"), "Missing main landmark");
    assert!(body.contains("<footer"), "Missing footer landmark");
    assert!(
        body.contains("/static/css/main.css"),
        "Missing CSS stylesheet link"
    );
    assert!(
        body.contains("aria-live=\"polite\""),
        "Missing aria-live region for HTMX announcements"
    );
    assert!(body.contains("<h1>Welcome</h1>"), "Missing h1");
}

#[tokio::test]
async fn static_css_is_served() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/static/css/main.css", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let content_type = response
        .headers()
        .get("content-type")
        .expect("Missing content-type header")
        .to_str()
        .unwrap();
    assert!(
        content_type.contains("text/css"),
        "Expected text/css, got {content_type}"
    );
}

use crate::helpers::spawn_app;

/// Helper to register a user via the registration endpoint.
async fn register_user(address: &str, email: &str, password: &str) {
    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{address}/register"))
        .form(&[
            ("email", email),
            ("password", password),
            ("password_confirmation", password),
        ])
        .send()
        .await
        .expect("Failed to register user");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Registration should succeed with 303"
    );
}

#[tokio::test]
async fn get_login_returns_200_with_login_form() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/login", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let content_type = response
        .headers()
        .get("content-type")
        .expect("Missing content-type header")
        .to_str()
        .unwrap();
    assert!(
        content_type.contains("text/html"),
        "Expected text/html, got {content_type}"
    );

    let body = response.text().await.unwrap();

    // Page structure
    assert!(body.contains("Sign in"), "Missing page heading");
    assert!(
        body.contains("Sign in -- Todo List"),
        "Missing descriptive page title"
    );

    // Form fields with labels
    assert!(
        body.contains("<label for=\"email\">Email</label>"),
        "Missing email label"
    );
    assert!(body.contains("type=\"email\""), "Missing email input");
    assert!(
        body.contains("autocomplete=\"email\""),
        "Missing autocomplete=\"email\" on email field"
    );
    assert!(
        body.contains("<label for=\"password\">Password</label>"),
        "Missing password label"
    );
    assert!(
        body.contains("autocomplete=\"current-password\""),
        "Missing autocomplete=\"current-password\" on password field"
    );

    // Submit button
    assert!(
        body.contains(">Sign in</button>"),
        "Submit button should say 'Sign in'"
    );

    // Link to register
    assert!(
        body.contains("Create account"),
        "Missing link to registration page"
    );
    assert!(
        body.contains("href=\"/register\""),
        "Missing register link href"
    );

    // Error container always in DOM (for aria-describedby) but empty on initial load
    assert!(
        body.contains("role=\"alert\""),
        "Error element with role=\"alert\" should always be in the DOM"
    );
    assert!(
        !body.contains("aria-invalid=\"true\""),
        "Should not have aria-invalid on initial load"
    );
    // The error element should be empty (no error text)
    assert!(
        !body.contains("didn&#39;t work"),
        "Should not show error message text on initial load"
    );
}

